fn Any_to_f64(a: &dyn Any) -> f64 {
    let mut a_f64 = 0.0;

    if a.downcast_ref::<f64>() == None {
        match a.downcast_ref::<&str>() {
            Some(as_string) => {
                a_f64 = as_string.parse::<f64>().unwrap();
            }
            None => {}
        }

        match a.downcast_ref::<i32>() {
            Some(as_i32) => {
                a_f64 = *as_i32 as f64;
            }
            None => {}
        }
    } else {
        a_f64 = *a.downcast_ref::<f64>().unwrap();
    }

